info.narration:
[
{$0 กำลังมองหากลิ่นของร่างกาย พร้อมกับรอยยิ้มของใครหลายคน}
]

[
{$0 กำลังรอคอยกลิ่นเลือดที่กำลังจะมาถึง พร้อมกับเสียงหัวเราะทั้งหมดของผู้ที่มองไม่เห็นที่นี่},
]

observe.desc:
			[
			{เรื่องแบบนี้ไม่ใช่เรื่องแปลกที่นี่ แต่แล้ววันหนึ่ง พนักงานหลายสิบคนก็ถูกสังหารในเหตุการณ์หนึ่ง สาเหตุเป็นเหมือนเดิมเสมอ บางสิ่งหลบหนีได้ พวกเขาพยายามหยุดมัน แล้วมันก็ทำให้เกิดการหลบหนีครั้งใหม่…

สิ่งหนึ่งที่โชคดีคือแผนกถูกปิดผนึกไว้ก่อนที่สิ่งต่างๆ จะแย่ลงไปกว่านี้ พวกเขาจึงเสียชีวิตในที่เดียวกันทั้งหมด พูดตามตัวอักษรก็คือมี 'ภูเขาศพ' ก่อตัวขึ้น เห็นได้ชัดว่าไม่มีใครต้องการทำความสะอาดความยุ่งเหยิงนั้น ตามปกติแล้วมันควรจะได้รับการดูแลภายในวันนั้น แต่เนื่องจากอุบัติเหตุนั้นน่าสยดสยองมากและทุกคนเหนื่อยล้ามาก การทำความสะอาดจึงถูกเลื่อนออกไปโดยได้รับอนุญาตจากเซฟิราห์ของแผนกนั้น อย่าถามผมว่ามันเป็นแผนกไหน ผมจำรายละเอียดทั้งหมดไม่ได้}
			]

			[
			{เมื่อปล่อยทิ้งไว้ในที่โล่ง ศพจะเริ่มเน่าเปื่อยภายในไม่กี่ชั่วโมง ศพส่วนใหญ่ที่เสียชีวิตที่นี่จะได้รับความเสียหายในรูปแบบใดรูปแบบหนึ่ง ทำให้พวกมันเน่าเปื่อยเร็วยิ่งขึ้น

คุณอาจจะยังไม่รู้ แต่พนักงานส่วนใหญ่ที่นี่ค่อนข้างเชี่ยวชาญในการทำความสะอาดศพ การทำความสะอาดซ้ำแล้วซ้ำเล่าจะทำให้ทุกคนเป็นผู้เชี่ยวชาญในเรื่องนี้ ไม่ว่าคุณจะต้องการหรือไม่ก็ตาม สมมติว่าคนที่คุณเพิ่งคุยเรื่องแผนการกินมื้อเย็นด้วยเสียชีวิตอย่างน่าสยดสยอง ด้วยประสบการณ์ที่ซ้ำแล้วซ้ำเล่าของคุณที่คอยช่วยเหลือ อย่างน้อยคุณก็จะไม่รู้สึกอยากอาเจียนหรือวิ่งหนี}
			]

[
{โอ้ ผมนอกเรื่องไปหน่อยนะ อย่างไรก็ตาม ภายใต้สถานการณ์ปกติ ภูเขาศพควรจะถูกกำจัดออกไปอย่างรวดเร็ว แต่มันกลับยังคงอยู่ในแผนกนั้นเป็นเวลานาน มันจึงเน่าเปื่อย ละลาย ผุกร่อน และย่อยสลายไปตามกฎของธรรมชาติ}
]

			[
			{นั่นคือจุดเริ่มต้นของการสร้างมันขึ้นมาจากภูเขาศพ พวกที่ตายไปแล้วได้มอบชีวิตให้กับบางสิ่ง คุณประหลาดใจแล้วใช่ไหม? ผมยังมีเรื่องจะเล่าให้ฟังอีกมาก พวกที่ตายไปแล้วหลอมรวมเข้าด้วยกัน ทั้งหมดกำลังยิ้ม พวกเขากำลังแบ่งปันส่วนต่างๆ ของร่างกายซึ่งกันและกัน อย่างน้อยก็ส่วนที่ยังคงสภาพสมบูรณ์ พวกเขากลายเป็นขาและปากของกันและกัน อย่างไรก็ตาม นั่นไม่ได้หมายความว่าจิตสำนึกของพวกเขากลับคืนมาด้วย มันต้องการเพียงสิ่งเดียว: เนื้อหนังของเราที่เปื้อนไปด้วยเลือด เมื่อมีการประกาศว่ามีคนเสียชีวิต สิ่งแรกที่คุณควรทำคือตรวจสอบว่าสิ่งนี้ถูกกักกันหรือไม่ เมื่อมันได้กลิ่น มันจะไล่ตามเราในทันที ใบหน้ายิ้มแย้มเหล่านั้นไม่คุ้นเคยแต่ก็เต็มไปด้วยความโศกเศร้า

ยิ่งมันเจอศพมากเท่าไหร่ รูปร่างของมันก็ยิ่งชัดเจนมากขึ้นเท่านั้น และมันก็ไม่เคยพอใจ

ผมบอกคุณทั้งหมดนี้เพราะมันเกือบจะมาถึงแล้ว อุบัติเหตุเกิดขึ้นที่นี่เสมอ บางคนอาจจะสละเวลาสักครู่เพื่อยืนสงบนิ่ง แต่ส่วนใหญ่จะหันหลังกลับและคิดว่า "อีกแล้วเหรอ?" อย่างน้อยสิ่งหนึ่งที่ทำได้ถูกต้องคือแผนกถูกปิดผนึกไว้ ผมก็เหลืออยู่คนเดียวแล้วนี่นะ คุณได้เรียนรู้อะไรจากเรื่องราวของผมไหม? คุณถามว่าเรื่องราวที่น่ากลัวแบบนี้จะเรียนรู้อะไรได้? มันคล้ายกับนิทานส่วนใหญ่ "อย่าขี้เกียจ" คือบทเรียน เมื่อเสียงของผมหยุดลง ให้มาที่นี่และทำความสะอาดเพื่อนร่วมงานของคุณในเวลา 3 นาที}
			]

			[
			{อีกไม่นานผมก็จะไม่สามารถพูดต่อไปได้แล้ว ผมกำลังจะกลืนระเบิดลูกใหญ่ เวลาใกล้หมดแล้ว เลือดไหลไปทั่วที่นี่ ผมเริ่มเห็นใบหน้ายิ้มแย้มแล้ว... บางสิ่งที่คุณไม่ค่อยได้เห็นรอบๆ ที่นี่

อย่าแปลกใจเมื่อคุณได้ยินเสียงระเบิดดัง อย่างที่ผมบอกไป มันคือ 3 นาทีพอดี ผมแน่ใจว่าระเบิดขนาดนี้จะสามารถยับยั้งมันได้

ศพสุดท้ายที่มันจะพบก็คือศพของผม}
			]
